output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?brother WHERE {
  wd:Q5108226 wdt:P3373 ?brother
}

args.sparql:
SELECT ?brother ?brotherBirth WHERE {
  wd:Q5108226 wdt:P224 ?brother.
  ?brother wdt:P569 ?brotherBirth.
  FILTER (datatype(?brotherBirth) = xsd:date)
} ORDER BY DESC(?brotherBirth) LIMIT 1
